using Microsoft.AspNetCore.Mvc;
using System.IO;
namespace FileUploaderApp.Controllers {  
    [Route("api/[controller]")]  // Route attribute to bind the controller with URLs in ASP Net Core MVC, e.g., api/FileController or /fileAPI etc...    
    public class FilesController : ControllerBase      
        {     
            private const string uploadFolderPath = "uploads";  
             [HttpGet("{filename}")]  // Route attribute to bind the method with URL in ASP Net Core MVC, e.g., api/Files or /fileAPI etc...    
              public IActionResult GetFile(string filename)    {     
                  var path = Path.Combine(Directory.GetCurrentDirectory(), uploadFolderPath ,filename);   // Combining the current directory and file name to get full absolute paths of files in 'uploads' folder      
                 if (!System.IO.File.Exists(path))     return NotFound();  // If File does not exist then Return a NOT FOUND status     
                  var contentType = MimeTypesMap.GetMimeType(Path.GetExtension(filename));   // Get the mimetype of file using extension name      
                 return File(path,contentType);    }    
        }}